fn:forward(pixel_values:FloatTensor|None, bool_masked_pos:BoolTensor|None=None)->(Tensor,) = 
  patch_embeddings(pixel_values) |> λembeddings,dims: (
    norm(embeddings), 
    dropout(embeddings) if bool_masked_pos is None else 
      embeddings*(1-mask)+(mask_tokens*mask) where mask=unsqueeze(-1)(bool_masked_pos).type_as(mask_tokens)
  )[0],dims
